export { default as SColorArea } from './color-area.vue';

export type * from '@soybeanjs/headless/color-area';
export type * from './types';

import type { ColorAreaCompactEmits, ColorAreaCompactProps, ColorAreaUi } from '@soybeanjs/headless/color-area';
import type { ClassValue } from '@soybeanjs/headless/types';
import type { ThemeSize } from '@/theme';

/**
 * Properties for the ColorArea component.
 */
export interface ColorAreaProps extends ColorAreaCompactProps {
  /**
   * Additional class names applied to the root element.
   */
  class?: ClassValue;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<ColorAreaUi>;
}

/**
 * Events for the ColorArea component.
 */
export type ColorAreaEmits = ColorAreaCompactEmits;

// @unocss-include
import { scv } from '@soybeanjs/cva';

export const colorAreaVariants = scv({
  slots: {
    root: 'relative select-none',
    area: [
      'relative overflow-hidden min-w-25 min-h-25 w-full h-full rounded-xl border border-input shadow-inner outline-none',
      'focus-visible:ring-3 focus-visible:ring-primary/20 data-[disabled]:opacity-60'
    ],
    thumb: [
      'absolute block rounded-full border-2 border-white bg-transparent shadow-lg',
      'ring-1 ring-black/20 transition-[transform,box-shadow] duration-150',
      'hover:scale-105 outline-none focus-visible:ring-4 focus-visible:ring-primary/25'
    ]
  },
  variants: {
    size: {
      xs: {
        root: 'text-2xs',
        thumb: 'size-3'
      },
      sm: {
        root: 'text-xs',
        thumb: 'size-3.5'
      },
      md: {
        root: 'text-sm',
        thumb: 'size-4'
      },
      lg: {
        root: 'text-base',
        thumb: 'size-4.5'
      },
      xl: {
        root: 'text-lg',
        thumb: 'size-5'
      },
      '2xl': {
        root: 'text-xl',
        thumb: 'size-6'
      }
    }
  },
  defaultVariants: {
    size: 'md'
  }
});

import type { ThemeSize } from './types';

export const themeSizeMap: Record<ThemeSize, number> = {
  xs: 12,
  sm: 14,
  md: 16,
  lg: 18,
  xl: 20,
  '2xl': 24
};
export const miniSizeMap: Record<ThemeSize, ThemeSize> = {
  xs: 'xs',
  sm: 'xs',
  md: 'sm',
  lg: 'md',
  xl: 'lg',
  '2xl': 'xl'
};

export const themeSizeRatio = Object.fromEntries(
  Object.entries(themeSizeMap).map(([key, value]) => [key, value / themeSizeMap.md])
) as Record<ThemeSize, number>;
